import json
from dataclasses import dataclass
from typing import List, Optional
from openai import OpenAI
from pydantic import BaseModel

client = OpenAI()

@dataclass
class ConsistencyTestCase:
    test_id: str
    input_message: str
    expected_format: str          # 'json' | 'single_word' | 'contains'
    expected_value: Optional[str] # For exact or contains checks
    required_json_keys: Optional[List[str]] = None
    runs: int = 10                # Number of times to run for consistency scoring

def run_agent(system_prompt: str, user_message: str) -> str:
    response = client.chat.completions.create(
        model="gpt-4o",
        temperature=0,
        messages=[
            {"role": "system", "content": system_prompt},
            {"role": "user", "content": user_message}
        ]
    )
    return response.choices[0].message.content.strip()

def evaluate_output(output: str, test: ConsistencyTestCase) -> bool:
    if test.expected_format == 'json':
        try:
            parsed = json.loads(output)
            if test.required_json_keys:
                return all(k in parsed for k in test.required_json_keys)
            return True
        except json.JSONDecodeError:
            return False
    elif test.expected_format == 'single_word':
        return output.upper() in (test.expected_value or "").split("|")
    elif test.expected_format == 'contains':
        return (test.expected_value or "").lower() in output.lower()
    return False

def run_consistency_suite(system_prompt: str, test_cases: List[ConsistencyTestCase]) -> dict:
    results = []
    all_passed = True

    for test in test_cases:
        pass_count = 0
        for _ in range(test.runs):
            output = run_agent(system_prompt, test.input_message)
            if evaluate_output(output, test):
                pass_count += 1

        consistency_rate = pass_count / test.runs
        passed = consistency_rate >= 0.95  # 95% threshold
        if not passed:
            all_passed = False

        results.append({
            "test_id": test.test_id,
            "consistency_rate": f"{consistency_rate:.0%}",
            "passed": passed,
            "runs": test.runs
        })
        print(f"[{'PASS' if passed else 'FAIL'}] {test.test_id}: {consistency_rate:.0%} consistency over {test.runs} runs")

    return {"all_passed": all_passed, "results": results}

# Define test cases
test_cases = [
    ConsistencyTestCase(
        test_id="sentiment_positive",
        input_message="I love this product, it works perfectly!",
        expected_format="single_word",
        expected_value="POSITIVE",
        runs=10
    ),
    ConsistencyTestCase(
        test_id="json_extraction",
        input_message="Extract from: Order 5678, 2 items, $45.00, shipped to Chicago.",
        expected_format="json",
        expected_value=None,
        required_json_keys=["order_id", "item_count", "total_amount", "destination"],
        runs=10
    )
]

system_prompt = "You are a precise data agent. For sentiment, respond with one word: POSITIVE, NEGATIVE, or NEUTRAL. For extraction, respond with valid JSON only."

print("Running consistency test suite...\n")
results = run_consistency_suite(system_prompt, test_cases)
print(f"\nOverall: {'ALL TESTS PASSED' if results['all_passed'] else 'SOME TESTS FAILED'}")
